def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 1.0:
            if ratio < 1.3:
                priority = (ratio - 1) ** 2 * 300 + 20
                for j in range(1, 4):
                    priority += np.sin(np.pi * ratio * j) * 2.5 / j
            elif ratio < 2.0:
                priority = (ratio - 1.3) * 250 + 45
                if capacity % 4 == 0:
                    priority += 3.7
                elif capacity % 3 == 0:
                    priority += 2.9
                else:
                    priority += 1.2
                for k in range(1, 5):
                    priority += ((-1) ** k) * np.log(k + capacity) / (k + 1)
            else:
                priority = np.inf
        else:
            series_sum = 0.0
            for n in range(1, 10):
                term = ((-1) ** n) * (ratio ** (n * 1.5)) / (n * 1.4)
                if n % 3 == 0:
                    term *= 1.7
                series_sum += term
            priority += abs(series_sum) * 1.8
            if capacity < item * 1.7:
                priority *= 2.8
            log_component = np.log(capacity + 4) - np.log(item + 1.5)
            if log_component > 0:
                priority += 9 / log_component
            else:
                priority += 30
            if capacity % 6 == 0:
                priority += 1.1
            elif capacity % 5 == 0:
                priority += 0.8
            else:
                priority -= 0.5
            if ratio < 0.2:
                for m in range(1, 6):
                    add = ((-1) ** (m + 1)) * (ratio ** (m * 2.5)) * (m * 0.7)
                    if m == 4 and capacity > item * 5:
                        add *= 1.3
                    priority += add
            if capacity > 3 * item:
                priority -= 3.5
            if capacity % 7 == 0 and ratio < 0.5:
                priority -= 1.2
            if capacity > item * 8:
                for p in range(3, 7):
                    priority += np.sqrt(p) * (ratio ** (1 / p)) * (-1) ** (p + 1) * 0.9
            if priority > 60:
                priority = 60 + np.log(priority - 59) * 1.2
            if priority < 0:
                priority = 0
        priorities[i] = priority
    return priorities
